const cfg = $('Set Config').first().json;
const raw = $input.first().json;

if (!raw.data || !raw.data.user) {
  throw new Error('Perfil nao encontrado ou sessao expirada. Verifique sessionid e csrftoken no Set Config.');
}

const user = raw.data.user;
const maxPosts = parseInt(cfg.max_posts) || 12;

const profile = {
  username:    user.username || '',
  full_name:   user.full_name || '',
  biography:   user.biography || '',
  followers:   (user.edge_followed_by && user.edge_followed_by.count) || 0,
  following:   (user.edge_follow && user.edge_follow.count) || 0,
  posts_count: (user.edge_owner_to_timeline_media && user.edge_owner_to_timeline_media.count) || 0,
  is_private:  user.is_private || false,
  is_verified: user.is_verified || false,
  profile_pic: user.profile_pic_url_hd || user.profile_pic_url || ''
};

const edges = (user.edge_owner_to_timeline_media && user.edge_owner_to_timeline_media.edges) || [];

const posts = edges.slice(0, maxPosts).map(function(e) {
  const cap = e.node.edge_media_to_caption && e.node.edge_media_to_caption.edges && e.node.edge_media_to_caption.edges[0];
  return {
    id:             e.node.id,
    shortcode:      e.node.shortcode,
    caption:        (cap && cap.node && cap.node.text) || '',
    likes:          (e.node.edge_liked_by && e.node.edge_liked_by.count) || 0,
    comments_count: (e.node.edge_media_to_comment && e.node.edge_media_to_comment.count) || 0,
    image_url:      e.node.display_url || '',
    timestamp:      e.node.taken_at_timestamp || 0,
    is_video:       e.node.is_video || false,
    profile: profile,
    cfg: {
      ig_session_id:     cfg.ig_session_id,
      ig_csrf_token:     cfg.ig_csrf_token,
      ig_app_id:         cfg.ig_app_id,
      user_agent:        cfg.user_agent,
      delay_min_ms:      parseInt(cfg.delay_min_ms) || 3000,
      delay_max_ms:      parseInt(cfg.delay_max_ms) || 8000,
      anthropic_api_key: cfg.anthropic_api_key
    }
  };
});

return posts.map(function(p) { return { json: p }; });

const post = $('Split In Batches').item.json;
const cfg  = post.cfg;
const raw  = $input.first().json;
const rawComments = (raw && raw.comments) || [];

const leadKws = [
  'quanto custa','quero comprar','manda inbox','como compro','tem a venda',
  'how much','want to buy','dm me','price?','where to buy','link?'
];

function esc(s) { return (s || '').replace(/'/g, "''").replace(/\n/g, ' ').substring(0, 2000); }
function escJ(s){ return (s || '').replace(/'/g, "''"); }

const comments = rawComments.map(function(c) {
  const text = c.text || '';
  const mentions = (text.match(/@([a-zA-Z0-9._]+)/g) || []).map(function(m){ return m.slice(1); });
  const hashtags = (text.match(/#([a-zA-Z0-9_]+)/g)  || []).map(function(h){ return h.slice(1); });
  return {
    comment_id: String(c.pk || c.id || ''),
    post_id:    post.id,
    username:   (c.user && c.user.username) || '',
    text:       text,
    mentions:   mentions,
    hashtags:   hashtags,
    is_lead:    leadKws.some(function(kw){ return text.toLowerCase().indexOf(kw) > -1; }),
    timestamp:  c.created_at || 0,
    likes:      c.comment_like_count || 0
  };
});

// --- Build profile INSERT ---
var p = post.profile;
var profile_query = [
  'INSERT INTO profiles (username, full_name, biography, followers, following, posts_count, is_private, is_verified)',
  'VALUES (',
  "  '" + esc(p.username) + "',",
  "  '" + esc(p.full_name) + "',",
  "  '" + esc(p.biography) + "',",
  '  ' + p.followers + ', ' + p.following + ', ' + p.posts_count + ',',
  '  ' + p.is_private + ', ' + p.is_verified,
  ')',
  'ON CONFLICT (username) DO UPDATE SET',
  '  followers   = EXCLUDED.followers,',
  '  following   = EXCLUDED.following,',
  '  posts_count = EXCLUDED.posts_count,',
  '  updated_at  = NOW()'
].join('\n');

// --- Build post INSERT ---
var post_query = [
  'INSERT INTO posts (id, username, caption, likes, comments, image_url, is_video, post_timestamp)',
  'VALUES (',
  "  '" + post.id + "',",
  "  '" + esc(p.username) + "',",
  "  '" + esc(post.caption) + "',",
  '  ' + post.likes + ', ' + post.comments_count + ',',
  "  '" + esc(post.image_url) + "',",
  '  ' + post.is_video + ',',
  '  to_timestamp(' + (post.timestamp || 0) + ')',
  ')',
  'ON CONFLICT (id) DO UPDATE SET',
  '  likes    = EXCLUDED.likes,',
  '  comments = EXCLUDED.comments'
].join('\n');

// --- Build comments bulk INSERT ---
var comments_query = 'SELECT 1 -- sem comentarios';
if (comments.length > 0) {
  var vals = comments.map(function(c) {
    var t = esc(c.text);
    var u = esc(c.username);
    var m = escJ(JSON.stringify(c.mentions));
    var h = escJ(JSON.stringify(c.hashtags));
    return "('"+c.comment_id+"','"+c.post_id+"','"+u+"','"+t+"','"+m+"'::jsonb,'"+h+"'::jsonb,"+c.is_lead+",to_timestamp("+(c.timestamp||0)+"),"+c.likes+")";
  }).join(',');
  comments_query = 'INSERT INTO comments (comment_id,post_id,username,comment,mentions,hashtags,is_lead,comment_timestamp,likes) VALUES ' + vals + ' ON CONFLICT (comment_id) DO NOTHING';
}

var commentsForAI = comments.map(function(c){ return '@' + c.username + ': ' + c.text; }).join('\n').substring(0, 8000);

return [{
  json: {
    profile_query:   profile_query,
    post_query:      post_query,
    comments_query:  comments_query,
    commentsForAI:   commentsForAI,
    lead_count:      comments.filter(function(c){ return c.is_lead; }).length,
    total_comments:  comments.length,
    post_username:   p.username,
    cfg:             cfg,
    post:            post
  }
}];
